VALUES
  ('disabled-57f41407-moex-00506', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', 'A 以 B 為被告起訴，先位之訴請求返還借款新臺幣（下同）50 萬元及給 付貨款70萬元，備位之訴請求B返還不當得利60萬元，則本件應以何金 額為訴訟標的金額徵收裁判費？', '["50萬元", "60萬元", "120萬元", "180萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00507', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於合意停止訴訟，下列敘述何者錯誤？', '["當事人得以合意停止訴訟程序", "合意停止訴訟時，不變期間之進行，不受影響", "合意停止訴訟，應由兩造向受訴法院或受命法官陳明", "合意停止訴訟程序之當事人，如於4個月內不續行訴訟者，法院應裁定 命其續行訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00508', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於公示送達，下列敘述何者正確？', '["對於當事人之送達，有應為送達之處所不明者，受訴法院得依聲請，准 為公示送達", "對於當事人之送達，有應為送達之處所不明，且無人為公示送達之聲請 者，受訴法院之書記官應依職權公示送達", "曾受送達之被告變更其受送達之處所，而未向法院陳報，致送達之處所 不明者，受訴法院之書記官應依職權公示送達", "公示送達，應由法院執達員保管應受送達之文書，而於法院網站公告曉 示其應受送達人可隨時領取"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00509', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於期間，下列敘述何者正確？', '["當事人應扣除之在途期間，由審判長依職權裁定之。當事人不服者，應 提起抗告", "當事人不在法院所在地住居者，計算法定期間，應扣除其在途之期間", "當事人因天災致遲誤不變期間，應於其原因消滅後 30 日內，向法院聲 請回復原狀", "當事人如遇重大事由，應向法院聲請延展不變期間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00510', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於訴訟上和解，下列敘述何者正確？', '["訴訟上和解成立，須經上級法院核定，始生效力", "訴訟上和解有得撤銷之原因，得提起撤銷和解之訴", "當事人就未聲明之事項成立訴訟上和解，得為執行名義", "訴訟上和解筆錄記載有錯誤之情形，由法院以裁定更正之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00511', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於自由心證與裁判，下列敘述何者正確？', '["審判長為裁判時，應斟酌調查事實之結果，依合議庭全體法官多數決之 自由心證，判斷當事人陳述之真偽", "當事人已證明受有損害，而不能證明其數額者，法院應審酌一切情況， 依所得心證定其數額", "法官依自由心證判斷事實之真偽，不受當事人不爭執事實之拘束", "通常訴訟事件之原告為訴訟標的之捨棄者，判決書得僅記載主文"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00512', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '原告於本案經第一審終局判決後撤回起訴，3 個月後就同一事件於有管轄 權之另一法院再為起訴，受訴法院應如何處理？', '["不經言詞辯論，逕以判決駁回之", "以裁定移送原判決法院", "以裁定命補正", "以裁定駁回之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00513', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於民事訴訟之反訴，下列敘述何者正確？', '["提起反訴應經法院准許", "原則上應向反訴被告住所地之法院提起反訴", "得於言詞辯論時以言詞提起反訴", "與本訴行不同種之訴訟程序者，亦得提起反訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00514', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲因乙超速闖紅燈，造成車損人傷，基於侵權行為法律關係，起訴請求乙 賠償損害。下列敘述何者錯誤？', '["甲就車損部分，原請求乙給付新臺幣（下同）30萬元，得於訴訟中增加 請求40萬元", "甲原請求乙賠償車損，得於訴訟中，不經乙同意，追加請求賠償精神慰 撫金", "甲於起訴狀毋庸載明所請求之金額，得待鑑定確認損害賠償金額之後再 補充即可", "甲原請求賠償 5 萬元，經訴之追加後，其訴訟標的金額逾 10 萬元但在 50萬元以下，如當事人合意且法院認為適當者，得續用小額訴訟程序"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00515', 'disabled-57f41407', 'disabled-57f41407-moex-111-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於判決確定之時點（不考慮在途期間及期間末日延展），下列敘述何者 正確？', '["敗訴被告於5月1日收受判決後，於5月25日提起上訴，經上訴審法院 以其上訴逾上訴期間而裁定駁回，該判決於5月21日確定", "敗訴被告於5月1日收受判決前捨棄上訴，該判決於捨棄時確定", "敗訴被告於5月1日收受判決後，於5月15日提起合法上訴，又於5月 25日撤回上訴，該判決於5月21日確定", "第一審法院所為之除權判決，於判決送達時確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "768f62303fcf", "answer_pdf_sha1": "d7be33bb3a54", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0408", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
